import java.util.*;

public class Solution {
    public static long solve(long n, long[][] edges) {
        int N = (int) n;
        long[] dist = new long[N];
        boolean[] hasUsed = new boolean[N];
        Arrays.fill(dist, Long.MAX_VALUE);
        dist[0] = 0;

        List<long[]>[] inEdges = new ArrayList[N];
        List<long[]>[] outEdges = new ArrayList[N];
        for (int i = 0; i < N; i++) {
            inEdges[i] = new ArrayList<>();
            outEdges[i] = new ArrayList<>();
        }

        for (long[] edge : edges) {
            int u = (int) edge[0];
            int v = (int) edge[1];
            long w = edge[2];
            outEdges[u].add(new long[]{v, w});
            inEdges[v].add(new long[]{u, w});
        }

        PriorityQueue<long[]> pq = new PriorityQueue<>(new Comparator<long[]>() {
            public int compare(long[] a, long[] b) {
                if (a[0] < b[0]) return -1;
                if (a[0] > b[0]) return 1;
                return 0;
            }
        });
        pq.offer(new long[]{0, 0});

        while (!pq.isEmpty()) {
            long[] node = pq.poll();
            long cost = node[0];
            int u = (int) node[1];
            if (hasUsed[u]) continue;
            hasUsed[u] = true;

            for (long[] outEdge : outEdges[u]) {
                int v = (int) outEdge[0];
                long w = outEdge[1];
                long newCost = cost + w;
                if (newCost < dist[v]) {
                    dist[v] = newCost;
                    pq.offer(new long[]{newCost, v});
                }
            }

            for (long[] inEdge : inEdges[u]) {
                int x = (int) inEdge[0];
                long w = inEdge[1];
                long newCost = cost + 2 * w;
                if (newCost < dist[x]) {
                    dist[x] = newCost;
                    pq.offer(new long[]{newCost, x});
                }
            }
        }

        return dist[N-1] == Long.MAX_VALUE ? -1 : dist[N-1];
    }
}
