public class Solution {
    public static long solve(long n, long[][] edges) {
        int nodeCount = (int) n;
        List<int[]>[] normalOut = new ArrayList[nodeCount];
        List<int[]>[] reverseIn = new ArrayList[nodeCount];

        for (int i = 0; i < nodeCount; i++) {
            normalOut[i] = new ArrayList<>();
            reverseIn[i] = new ArrayList<>();
        }

        for (long[] edge : edges) {
            int from = (int) edge[0];
            int to = (int) edge[1];
            int w = (int) edge[2];
            normalOut[from].add(new int[]{to, w});
            reverseIn[to].add(new int[]{from, w});
        }

        long inf = Long.MAX_VALUE;
        long[][] dist = new long[nodeCount][2];
        for (int i = 0; i < nodeCount; i++) {
            dist[i][0] = inf;
            dist[i][1] = inf;
        }
        dist[0][0] = 0;

        PriorityQueue<long[]> pq = new PriorityQueue<>(Comparator.comparingLong(a -> a[0]));
        pq.offer(new long[]{0, 0, 0});

        while (!pq.isEmpty()) {
            long[] cur = pq.poll();
            long d = cur[0];
            int u = (int) cur[1];
            int s = (int) cur[2];

            if (d != dist[u][s]) 
                continue;

            if (s == 0) {
                for (int[] edge : normalOut[u]) {
                    int v = edge[0];
                    long w = edge[1];
                    long nd = d + w;
                    if (dist[v][0] > nd) {
                        dist[v][0] = nd;
                        pq.offer(new long[]{nd, v, 0});
                    }
                }
                for (int[] edge : reverseIn[u]) {
                    int v = edge[0];
                    long w = edge[1];
                    long nd = d + 2 * w;
                    if (dist[v][0] > nd) {
                        dist[v][0] = nd;
                        pq.offer(new long[]{nd, v, 0});
                    }
                }
                if (dist[u][1] > d) {
                    dist[u][1] = d;
                    pq.offer(new long[]{d, u, 1});
                }
            } else {
                for (int[] edge : normalOut[u]) {
                    int v = edge[0];
                    long w = edge[1];
                    long nd = d + w;
                    if (dist[v][0] > nd) {
                        dist[v][0] = nd;
                        pq.offer(new long[]{nd, v, 0});
                    }
                }
            }
        }

        long ans = Math.min(dist[nodeCount-1][0], dist[nodeCount-1][1]);
        if (ans >= inf) 
